// src/pages/MainPage/index.jsx (Финальная версия)

import React, { useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { Link } from 'react-router-dom';
import { fetchCategories } from '../../store/slices/categoriesSlice';
import { fetchAllProducts } from '../../store/slices/productsSlice';
import CategoryItem from '../../components/CategoryItem';
import ProductCard from '../../components/ProductCard';
import CouponForm from '../../components/CouponForm';
import Button from '../../components/UI/Button';
import { BASE_URL } from '../../utils/api';
import s from './MainPage.module.css';


import bannerImage from '../../assets/images/garden_banner.png';
import handsImage from '../../assets/images/hands.png';

// -------------------------------------------------------------------

// 🔑 Вспомогательная функция для создания полного URL изображения
const getFullImageUrl = (imagePath) => {
    if (!imagePath) return '';
    // Формируем полный адрес: BASE_URL + путь, который пришел из API
    return `${BASE_URL}${imagePath.startsWith('/') ? '' : '/'}${imagePath}`;
};

const MainPage = () => {
  const dispatch = useDispatch();

  // 🔑 Используем данные категорий из Redux Store
  const { list: allCategories, status: categoriesStatus } = useSelector(state => state.categories); 
  const allProducts = useSelector(state => state.products.list);

  // Отображаем только первые 4 загруженные категории
  const mainPageCategories = allCategories.slice(0, 4); 

  const discountedProducts = allProducts
    .filter(p => p.discont_price !== null && p.discont_price < p.price)
    .slice(0, 4);

  useEffect(() => {
    if (categoriesStatus === 'idle') dispatch(fetchCategories()); 
    dispatch(fetchAllProducts());
  }, [dispatch, categoriesStatus]);

  return (
    <div className={s.mainContainer}>

      {/* 1. HERO BANNER */}
      <section 
        className={s.heroBanner}
        style={{ backgroundImage: `url(${bannerImage})` }} 
      >
        <div className={s.heroContent}>
          <h1>Amazing Discounts on Garden Products!</h1>
          <Button className={s.heroBtn}>Check out</Button>
        </div>
      </section>

      {/* 2. CATEGORIES */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
          <h2>Categories</h2>
          <div className={s.line}></div>
          <Link to="/categories">
            <button className={s.outlineBtn}>All categories</button>
          </Link>
        </div>

        {/* 🔑 ИСПОЛЬЗУЕМ ДАННЫЕ ИЗ REDUX (mainPageCategories) */}
        <div className={s.categoriesGrid}>
          {mainPageCategories.map(cat => (
              <CategoryItem 
                key={cat.id} 
                id={cat.id}
                title={cat.title}
                // 🔑 ПЕРЕДАЕМ ПОЛНЫЙ URL ИЗОБРАЖЕНИЯ
                image={getFullImageUrl(cat.image)}
              />
            ))
          }
          {/* УСЛОВИЕ ДЛЯ ПУСТОГО МАССИВА */}
          {mainPageCategories.length === 0 && categoriesStatus !== 'loading' && (
              <p>No categories found.</p>
          )}
        </div>
      </section>

     {/* 3. скидка */}
      <section className={s.discountSection}>
        <div className={s.discountContent}>
          <h2>5% off on the first order</h2>
          <div className={s.discountLayout}>
            <div className={s.imageWrapper}>
              <img src={handsImage} alt="Hands" />
            </div>
            <div className={s.formWrapper}>
              {/* 🔑 ИСПОЛЬЗУЕМ formClassName ВМЕСТО className И УДАЛЯЕМ s={s} */}
              <CouponForm formClassName={s.customForm} /> 
            </div>
          </div>
        </div>
      </section>


      {/* 4. SALE */}
      <section className={s.section}>
        <div className={s.sectionHeader}>
            <h2>Sale</h2>
            <div className={s.line}></div>
            <Link to="/products">
                <button className={s.outlineBtn}>All sales</button>
            </Link>
        </div>
        <div className={s.productsGrid}>
          {discountedProducts.map(product => (
            <ProductCard 
                key={product.id} 
                {...product} 
                // ⚠️ Убедитесь, что ProductCard использует getFullImageUrl, если изображения продуктов тоже с бэкенда
            />
          ))}
        </div>
      </section>

    </div>
  );
};

export default MainPage;
